            &mut filter_users_opt,
            &mut entries_buf_ptr,
            &mut entry_count,
        )
    };
    let mut candidate_root: *mut u8 = core::ptr::null_mut();
    let mut candidate_count: u64 = 0;
    let mut entries_base: *mut u8 = entries_buf_ptr;
    let mut i: usize = 0;
