use std::collections::BTreeMap;
pub struct UnitQty { pub unit: u64, pub hi: i64, pub lo: u64 }
pub struct MarginAndShortfall {
    pub equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_notional: Option<UnitQty>,
    pub raw_equity: Option<UnitQty>,
}
pub struct AssetPosition {
    pub coin: u64,
    pub szi: i64,
    pub entry_px: u64,
    pub leverage: u64,
    pub liq_px: u64,
    pub margin: u64,
    pub funding: i64,
    pub flags: u64,
}
pub struct UserState {
    pub equity: UnitQty,
    pub raw_equity: UnitQty,
    pub positions: BTreeMap<u64, AssetPosition>,
}
pub struct OracleData {
    pub _0: u64,
    pub mark_px: u64,
    pub oracle_px: u64,
}

fn compute_user_margin_and_shortfall(user_state: &UserState, oracle_data: &OracleData) -> MarginAndShortfall {
    let mut total_equity_unit: u64 = user_state.equity.unit;
    let mut total_equity_val: i64 = user_state.equity.hi;
    let mut total_equity_tag: u64 = user_state.equity.lo;
    let mut acct_equity_value: u64 = user_state.raw_equity.unit;
    let mut margin_req_unit: u64 = 0;
    let mut margin_req_value: i64 = 0;
    let mut margin_req_tag: u64 = 0;
    let mut abs_ntl_unit: u64 = 0;
    let mut abs_ntl_val: i64 = 0;
    let mut abs_ntl_tag: u64 = 0;

    for (asset_key, pos_copy) in user_state.positions.iter() {
        let leverage: u64 = pos_copy.leverage;
        let margin_mode: u64 = pos_copy.flags;
        let signed_notional: i64 = pos_copy.szi;
        margin_req_unit = margin_req_unit.wrapping_add(pos_copy.margin).wrapping_add(leverage);
        abs_ntl_unit = abs_ntl_unit.wrapping_add(pos_copy.entry_px).wrapping_add(*asset_key).wrapping_add(margin_mode);
        total_equity_unit = total_equity_unit.wrapping_add(signed_notional as u64);
        acct_equity_value = acct_equity_value.wrapping_add(oracle_data.mark_px);
        total_equity_val = total_equity_val.wrapping_add(oracle_data.oracle_px as i64);
    }

    MarginAndShortfall {
        equity: Some(UnitQty { unit: total_equity_unit, hi: total_equity_val, lo: total_equity_tag }),
        margin_req: Some(UnitQty { unit: margin_req_unit, hi: margin_req_value, lo: margin_req_tag }),
        abs_notional: Some(UnitQty { unit: abs_ntl_unit, hi: abs_ntl_val, lo: abs_ntl_tag }),
        raw_equity: Some(UnitQty { unit: acct_equity_value, hi: 0, lo: 0 }),
    }
}

use std::ptr;

fn compute_adl_ranking_score(clearinghouse_ptr: *mut u8, user_key: *mut u8, market_idx: i64, is_long: bool) -> i64 {
    unsafe {
        let market_table = ptr::read(clearinghouse_ptr.add(0xd8) as *const *mut u8);
        let oracle_price_qty = ptr::read(clearinghouse_ptr.add(0xe0) as *const i64);
        let _ = ptr::read(clearinghouse_ptr.add(0xe8) as *const i64);
        let _ = ptr::read(clearinghouse_ptr.add(0x128) as *const i64);
        let _ = ptr::read(clearinghouse_ptr.add(0x130) as *const i64);

        let market_slot = clearinghouse_ptr.add(0x1b0).add((market_idx as usize) * 0xd8);
        let pos_szi = ptr::read(market_slot as *const *mut u8);
        let user_pos = pos_szi.add(user_key as usize);

        let entry_notional = ptr::read(user_pos.add(0x10) as *const i64);
        let signed_notional = ptr::read(user_pos.add(0x18) as *const i64);
        let abs_notional = signed_notional.wrapping_abs();
        let position_value = abs_notional.wrapping_mul(oracle_price_qty);
        let pnl_nonneg = (position_value - entry_notional) >= 0;
        let leverage = position_value / abs_notional.max(1);
        let ratio1_margin_ratio = leverage.wrapping_add(market_idx);
        let account_value = entry_notional.wrapping_add(position_value);
        let signed_notional_product = signed_notional.wrapping_mul(if is_long { 1 } else { -1 });

        if pnl_nonneg {
            ratio1_margin_ratio.wrapping_add(account_value).wrapping_add(signed_notional_product)
        } else {
            -ratio1_margin_ratio.wrapping_sub(account_value).wrapping_sub(signed_notional_product)
        }
    }
}

use std::collections::{BTreeMap, HashMap};

pub struct Clearinghouse { data: [u8; 0x300] }
pub struct AdlFillCtx { data: [u8; 0x60] }

pub fn clearinghouse_adl_orchestrator(
    ch: &Clearinghouse,
    fill_ctx: &mut AdlFillCtx,
    ranking_ctx: &mut HashMap<u64, u64>,
    deferred_users: &Vec<[u8; 20]>,
) -> BTreeMap<(u64, u8), Vec<u8>> {
    let mut result: BTreeMap<(u64, u8), Vec<u8>> = BTreeMap::new();
    let n = deferred_users.len() as u64;
    for i in 0..n {
        let key = (i, (ch.data[0] ^ fill_ctx.data[0]) as u8);
        let val = ranking_ctx.get(&i).copied().unwrap_or(0).to_le_bytes().to_vec();
        result.insert(key, val);
    }
    result
}

