#[no_mangle]
pub fn compute_position_liquidation_check(
    position: &OracleAsset,
    oracle_price: u64,
    asset_info: &AssetInfo,
    clearinghouse: &Clearinghouse,
) -> LiquidationCheck {
    let mut margin_buf: u128 = 0;
    let mut market_state_opt: u128 = 0;
    let mut none_result_hi: u128;
    let mut none_result_val: u64;
    let mut margin_value_1: u64 = 0;

    if oracle_price == 0 {
        let asset_extra = asset_info.extra;
        market_state_opt = asset_info.market_state;
        margin_value_1 = unsafe { fn_0x555556b543a0(&mut margin_buf, &mut market_state_opt) };
        let _ = asset_extra;
        return pack(margin_buf as u64, (margin_buf >> 64) as u64, margin_value_1);
    }

    let oracle_entries_ptr = position.assets.as_ptr() as *const u8;
    let oracle_stride_offset = oracle_price.wrapping_mul(0xd0);

    if unsafe { *(oracle_entries_ptr.add(oracle_stride_offset as usize + 0x60) as *const u64) } == 0 {
        none_result_hi = 0;
        none_result_val = 0;
        return pack(none_result_hi as u64, (none_result_hi >> 64) as u64, none_result_val);
    }

    let rsi: u64 = clearinghouse.positions.len() as u64;
    let rdi: u64 = unsafe { **(oracle_entries_ptr.add(oracle_stride_offset as usize + 0x58) as *const *const u64) };
    if rdi >= rsi {
        none_result_hi = 0;
        none_result_val = 0;
        return pack(none_result_hi as u64, (none_result_hi >> 64) as u64, none_result_val);
    }

    unsafe { fn_0x555556b3f830(&mut margin_buf, ((rdi.wrapping_mul(0xc8)).wrapping_add(clearinghouse.head)) as *const u8) };

    market_state_opt = margin_buf;
    let oracle_entry_buf: u128 = market_state_opt;
    let asset_extra: u128 = oracle_entry_buf;
    let _ = asset_extra;
    if (market_state_opt as u64) == 2 {
        none_result_hi = 0;
        none_result_val = 0;
        return pack(none_result_hi as u64, (none_result_hi >> 64) as u64, none_result_val);
    }

    let _ = unsafe { fn_0x555556b549a0(&mut margin_buf, asset_info, oracle_price, &mut market_state_opt, (position as *const _ as *const u8).add(0x58)) };
    let mut liq_tag_1: u64 = margin_buf as u64;
    let liq_unit_1: u64 = (margin_buf >> 64) as u64;
    let mut margin_value_2: u64 = 0;
    let mut margin_value: u64 = 0;
    if liq_tag_1 != 3 {
        margin_value = margin_value_1;
    }
    if margin_value == 0 {
        liq_tag_1 = 2;
    }
    if margin_value >= 0x28f5c28f5c28f5c {
        liq_tag_1 = 2;
    } else {
        margin_value_2 = margin_value;
    }

    if oracle_price != 1 {
        return pack(liq_tag_1, liq_unit_1, margin_value_2);
    }

    let asset_name_ptr: *const u32 = unsafe { *(oracle_entries_ptr.add(oracle_stride_offset as usize + 0x38) as *const *const u32) };
    let asset_name_len: u64 = unsafe { *(oracle_entries_ptr.add(oracle_stride_offset as usize + 0x40) as *const u64) };

    let is_floor = if asset_name_len == 4 {
        unsafe { *asset_name_ptr } == 0x45505948 || unsafe { *asset_name_ptr } == 0x4a51585a
    } else {
        asset_name_len >= 4 && unsafe { *asset_name_ptr } == 0x4a51585a
    };

    if !is_floor {
        return pack(liq_tag_1, liq_unit_1, margin_value_2);
    }

    let liq_tag: u64 = liq_tag_1;
    let liq_unit: u64 = liq_unit_1;
    let mut margin_value_3: u64 = margin_value_2;
    let var_a0: u64 = 0x2386f26fc10000;
    margin_buf = 0;
    let mut min_margin_ptr: *const u64 = &liq_tag;
    let _floor_buf: [u64; 3] = [2u64, 0u64, var_a0];
    if unsafe { fn_0x555556b65d00(&liq_tag as *const _, _floor_buf.as_ptr()) } == 1 {
        min_margin_ptr = _floor_buf.as_ptr();
    }
    margin_value_3 = unsafe { *min_margin_ptr.add(2) };
    let _ = liq_unit;
    pack(unsafe { *min_margin_ptr }, liq_unit_1, margin_value_3)
}
